stp.writeLog("Start: CAA Response");
stp.setAutoProcess(true);
stp.setUserId("CSBANK");
var sMainRef = stp.getMsgTagVal("FA_CE_MAIN_REF");
stp.writeLog("sMainRef======================"+sMainRef);
stp.setMainRef(sMainRef);
stp.updateFieldValue("PARENT_MAIN_REF",sMainRef);
var sUnitCode = stp.getMsgTagVal("FA_SEL_ID");
stp.setCmpId(sUnitCode);
stp.updateFieldValue("CURRNT_STATUS","CAA Response");
stp.writeLog("End: CAA Response");
